class Solution:
    def furthestDistanceFromOrigin(self, moves: str) -> int:
        left = 0
        right = 0
        underscores = 0

        for move in moves:
            if move == 'L':
                left += 1
            elif move == 'R':
                right += 1
            else:
                underscores += 1

        return abs(left - right) + underscores
